solution_code:
#include <iostream>
#include <iomanip>

struct Reading
{
    char grade;
    double value;
    int id;
};

int main()
{
    int n;
    std::cin >> n;

    Reading data[5];

    for (int i = 0; i < n; ++i)
    {
        char g;
        double v;
        int id;
        std::cin >> g >> v >> id;
        data[i] = Reading{ g, v, id };
    }

    std::cout << std::fixed << std::setprecision(1);

    for (int i = 0; i < n; ++i)
    {
        std::cout << "Sensor " << data[i].id << ": "
                  << data[i].value << " [Grade "
                  << data[i].grade << "]\n";
    }

    std::size_t memberSum = sizeof(char) + sizeof(double) + sizeof(int);
    std::size_t actual = sizeof(Reading);

    std::cout << '\n';
    std::cout << "sizeof(char) + sizeof(double) + sizeof(int) = " << memberSum << '\n';
    std::cout << "sizeof(Reading) = " << actual << '\n';
    std::cout << "Padding bytes = " << actual - memberSum << '\n';

    return 0;
}
